class Solution {
    public long maximumTripletValue(int[] nums) {
        long maxVal = 0;
        for (int i = 0; i < nums.length - 2; i++) {
            for (int j = i + 1; j < nums.length - 1; j++) {
                for (int k = j + 1; k < nums.length; k++) {
                    maxVal = Math.max(maxVal, (long)(nums[i] - nums[j]) * nums[k]);
                }
            }
        }
        return maxVal;
    }
}
